```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return 1; // Connection failed
  }

  // 2. Begin a transaction
  auto begin_result = conn_result.and_then(sqlgen::begin_transaction);
  if (!begin_result) {
    return 1; // Transaction begin failed
  }

  // 3. Delete users where last_login is less than '2025-01-01'
  auto delete_result = begin_result.and_then(
      sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01")
  );
  if (!delete_result) {
    return 1; // Delete operation failed
  }

  // 4. Commit the transaction
  auto commit_result = delete_result.and_then(sqlgen::commit);
  if (!commit_result) {
    return 1; // Commit failed
  }

  // 5. Return the operation result of commit (0 for success)
  return 0;
}

} // namespace delete_inactive_users
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Transaction Management**: Chains operations using `and_then()` for proper error handling
3. **Where Condition**: Uses column literal `"last_login"_c` with comparison operator `<` against the date string
4. **Fluent API**: Properly chains `delete_from<User>` with `where()` condition using `operator|`
5. **Error Handling**: Checks each operation result and returns appropriate exit codes
6. **Return Value**: Returns `0` for successful commit, `1` for any operation failure

