```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    using namespace sqlgen::literals;

    // 1. Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = *conn_result;

    // 2. Begin a transaction
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    try {
        // 3. Update records using batched operation with IN clause
        auto update_stmt = sqlgen::update<Document>(
            "is_deleted"_c.set(1),
            "deleted_at"_c.set(sqlgen::CURRENT_TIMESTAMP)
        ) | sqlgen::where("doc_id"_c.in(ids));

        // 4. Execute the update statement
        auto update_result = update_stmt(conn);
        if (!update_result) {
            conn->rollback();
            return false;
        }

        // 5. Commit the transaction
        auto commit_result = conn->commit();
        if (!commit_result) {
            conn->rollback();
            return false;
        }

        return true;

    } catch (...) {
        // 6. Rollback on failure
        conn->rollback();
        return false;
    }
}

}  // namespace soft_delete_records
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Transaction Management**: 
   - Begins transaction with `conn->begin_transaction()`
   - Commits on success with `conn->commit()`
   - Rolls back on failure with `conn->rollback()`

3. **Batched Update with IN Clause**:
   - Uses `sqlgen::update<Document>()` with multiple set operations
   - Chains `sqlgen::where()` with `in()` condition for batch processing
   - Leverages the `operator|` syntax for fluent API

4. **Column Operations**:
   - Uses string literals with `_c` suffix (`"is_deleted"_c`, `"deleted_at"_c`, `"doc_id"_c`)
   - Applies `set()` operations for both fields
   - Uses `sqlgen::CURRENT_TIMESTAMP` for timestamp

5. **Error Handling**: Comprehensive error checking at each step with proper transaction rollback

This implementation follows all the specified requirements and leverages the sqlgen library's features effectively for batched soft delete operations with proper transaction management.

