```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = conn | sqlgen::begin_transaction;
  if (!begin_result) {
    return false;
  }

  auto transaction = begin_result.value();

  // Read from_account balance
  auto from_account_result = transaction | sqlgen::read<Account> 
                                   | sqlgen::where("account_id"_c == from_account_id);

  if (!from_account_result) {
    transaction | sqlgen::rollback;
    return false;
  }

  auto from_account = from_account_result.value();

  // Check sufficient funds
  if (from_account.balance < amount) {
    transaction | sqlgen::rollback;
    return false;
  }

  // Update from_account (deduct amount)
  auto update_from_result = transaction | sqlgen::update<Account>(
      "balance"_c.set("balance"_c - amount)
    ) | sqlgen::where("account_id"_c == from_account_id && "balance"_c >= amount);

  if (!update_from_result) {
    transaction | sqlgen::rollback;
    return false;
  }

  // Update to_account (add amount)
  auto update_to_result = transaction | sqlgen::update<Account>(
      "balance"_c.set("balance"_c + amount)
    ) | sqlgen::where("account_id"_c == to_account_id);

  if (!update_to_result) {
    transaction | sqlgen::rollback;
    return false;
  }

  // Commit transaction
  auto commit_result = transaction | sqlgen::commit;
  if (!commit_result) {
    transaction | sqlgen::rollback;
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds
```

