#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Connection failed
  }
  auto conn = conn_result.value();

  // 2. Create UPDATE statement for Order table
  // 3. Set status to 'expired' for pending orders older than 7 days
  auto update_expired = sqlgen::update<Order>(
      sqlgen::col<"status"> | sqlgen::set("expired")
  ).where(
      (sqlgen::col<"status"> == "pending") && 
      (sqlgen::col<"order_date"> < sqlgen::sqlite::date("now", "-7 days"))
  );

  // 4. Set status to 'delivered' for shipped orders (simulated)
  auto update_delivered = sqlgen::update<Order>(
      sqlgen::col<"status"> | sqlgen::set("delivered")
  ).where(sqlgen::col<"status"> == "shipped");

  // 5. Execute both UPDATE statements and get row counts
  auto result1 = update_expired(conn);
  auto result2 = update_delivered(conn);

  // 6. Return total number of rows affected by both updates
  if (!result1 || !result2) {
    return -1; // Update failed
  }

  return result1.value() + result2.value();
}

} // namespace update_order_status
```

