      inner_join<Sale, "t1">("product_id"_t2 == "product_id"_t1) |
      group_by("name"_t2);
  const auto create_view = create_as<SalesSummary>(summary_query) | if_not_exists;
  auto res = create_view(conn);

  return res.has_value();
