JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Create SQLite database connection
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables with if_not_exists flag
  auto create_dept = sqlgen::create_table<Department>;
  create_dept.if_not_exists_ = true;
  create_dept(conn);

  auto create_emp = sqlgen::create_table<Employee>;
  create_emp.if_not_exists_ = true;
  create_emp(conn);

  // 3. Insert data using write function
  sqlgen::write(conn, depts);
  sqlgen::write(conn, emps);

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
    ) | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
      | sqlgen::to<std::vector<JoinResult>>;

  auto inner_results = inner_query(conn).value();
  JoinAnalysis analysis{.inner_join_results = inner_results};

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2,
      "department_name"_t1
    ) | sqlgen::left_join<Department, "d">("department_id"_t2 == "department_id"_t1)
      | sqlgen::to<std::vector<JoinResult>>;

  auto left_results = left_query(conn).value();
  analysis.left_join_results = left_results;

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
    ) | sqlgen::right_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
      | sqlgen::to<std::vector<JoinResult>>;

  auto right_results = right_query(conn).value();
  analysis.right_join_results = right_results;

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
    ) | sqlgen::full_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
